"""Вкладка «Таблица».Три уровня иерархии (`QTreeWidget`):    1) Эксперимент (= серия запуска моделирования): timestamp, сигнал, шум,       количество фильтров, количество испытаний;    2) Фильтр: агрегированные метрики (среднее по N) и количество испытаний;    3) Испытание: номер, seed, все метрики.Каждый новый запуск моделирования добавляет ОТДЕЛЬНЫЙ узел верхнего уровня,а не дописывается в уже существующий — это логически разделяет разныеэксперименты одной сессии."""from __future__ import annotationsimport mathfrom typing import Iterablefrom PySide6.QtCore import Qtfrom PySide6.QtGui import QFontfrom PySide6.QtWidgets import (    QHBoxLayout, QPushButton, QTreeWidget, QTreeWidgetItem, QVBoxLayout, QWidget,)from ...core.types import ExperimentResult, ExperimentSeries_HEADERS: list[str] = [    "Эксперимент / Фильтр / Испытание",  # колонка-дерево    "N / №",                              # кол-во испытаний или номер    "Seed",    "MSE", "RMSE",    "SNR до, дБ", "SNR после, дБ", "ΔSNR, дБ", "Корреляция",]def _fmt_float(v: float, fmt: str = "{:.6g}") -> str:    if v is None or (isinstance(v, float) and math.isnan(v)):        return "—"    if isinstance(v, float) and math.isinf(v):        return "+∞" if v > 0 else "-∞"    return fmt.format(v)class ResultsTableTab(QWidget):    def __init__(self, parent: QWidget | None = None) -> None:        super().__init__(parent)        self._tree = QTreeWidget()        self._tree.setColumnCount(len(_HEADERS))        self._tree.setHeaderLabels(_HEADERS)        self._tree.setAlternatingRowColors(True)        self._tree.setUniformRowHeights(True)        self._tree.setSortingEnabled(False)        self._tree.setRootIsDecorated(True)        self._tree.setItemsExpandable(True)        self._tree.setColumnWidth(0, 340)        mono = QFont("Monospace")        mono.setStyleHint(QFont.TypeWriter)        self._tree.setFont(mono)        self._btn_expand = QPushButton("Развернуть всё")        self._btn_expand.clicked.connect(self._tree.expandAll)        self._btn_collapse = QPushButton("Свернуть всё")        self._btn_collapse.clicked.connect(self._tree.collapseAll)        top = QHBoxLayout()        top.addWidget(self._btn_expand)        top.addWidget(self._btn_collapse)        top.addStretch(1)        lay = QVBoxLayout(self)        lay.setContentsMargins(4, 4, 4, 4)        lay.addLayout(top)        lay.addWidget(self._tree)        # Автоинкрементный счётчик номеров экспериментов в рамках сессии.        self._next_experiment_no: int = 1    # ---------- публичный API -----------------------------------------------    def append_series(self, series: ExperimentSeries) -> None:        """Добавить ещё один эксперимент в таблицу отдельным узлом."""        exp_no = self._next_experiment_no        self._next_experiment_no += 1        exp_node = QTreeWidgetItem(self._tree)        exp_title = (            f"Эксперимент {exp_no}  [{series.timestamp}]  "            f"сигнал: «{series.signal_name}», шум: «{series.noise_name}»"        )        exp_node.setText(0, exp_title)        exp_node.setText(            1,            f"фильтров: {len(series.filter_names)}, "            f"испытаний: {series.n_trials}",        )        # Остальные колонки на уровне эксперимента — пустые.        for col in range(2, len(_HEADERS)):            exp_node.setText(col, "")        # Подсказка по узлу эксперимента.        exp_node.setToolTip(            0,            f"Эксперимент № {exp_no}\n"            f"Время (UTC): {series.timestamp}\n"            f"Сигнал: {series.signal_name}\n"            f"Шум: {series.noise_name}\n"            f"Режим seed: {series.seed_mode}\n"            f"Фильтров: {len(series.filter_names)}\n"            f"Испытаний: {series.n_trials}",        )        bold = QFont(self._tree.font())        bold.setBold(True)        for col in range(len(_HEADERS)):            exp_node.setFont(col, bold)        # Уровень 2 — фильтры.        for fname in series.filter_names:            runs = series.results.get(fname, [])            agg = series.aggregates.get(fname)            filter_node = QTreeWidgetItem(exp_node)            filter_node.setText(0, f"Фильтр: {fname}")            filter_node.setText(                1, str(agg.n_trials) if agg else str(len(runs))            )            filter_node.setText(2, "—")            if agg is not None:                filter_node.setText(3, _fmt_float(agg.mse_mean, "{:.4e}"))                filter_node.setText(4, _fmt_float(agg.rmse_mean, "{:.4e}"))                filter_node.setText(5, _fmt_float(agg.snr_before_db_mean, "{:.3f}"))                filter_node.setText(6, _fmt_float(agg.snr_after_db_mean, "{:.3f}"))                filter_node.setText(7, _fmt_float(agg.snr_improvement_db_mean,                                                  "{:+.3f}"))                filter_node.setText(8, _fmt_float(agg.correlation_mean, "{:.4f}"))                filter_node.setToolTip(                    0,                    f"{fname} — агрегат по {agg.n_trials} испытаниям\n"                    f"MSE:  {agg.mse_mean:.4e} ± {agg.mse_std:.2e}\n"                    f"RMSE: {agg.rmse_mean:.4e} ± {agg.rmse_std:.2e}\n"                    f"SNR до:    {agg.snr_before_db_mean:.3f} "                    f"± {agg.snr_before_db_std:.3f}\n"                    f"SNR после: {agg.snr_after_db_mean:.3f} "                    f"± {agg.snr_after_db_std:.3f}\n"                    f"ΔSNR:      {agg.snr_improvement_db_mean:+.3f} "                    f"± {agg.snr_improvement_db_std:.3f}\n"                    f"corr:      {agg.correlation_mean:.4f} "                    f"± {agg.correlation_std:.4f}",                )            # Средние столбцы в узле фильтра — полужирные.            for col in range(len(_HEADERS)):                filter_node.setFont(col, bold)                filter_node.setTextAlignment(                    col,                    Qt.AlignLeft | Qt.AlignVCenter if col == 0                    else Qt.AlignRight | Qt.AlignVCenter,                )            # Уровень 3 — отдельные испытания.            for r in runs:                self._append_trial(filter_node, r)            # Для одиночных испытаний автораскрываем узел фильтра.            if series.n_trials == 1:                filter_node.setExpanded(True)        # Эксперимент сразу разворачиваем, чтобы были видны фильтры.        exp_node.setExpanded(True)        # Подогнать ширины колонок один раз для наглядности.        if self._tree.topLevelItemCount() == 1:            for i in range(1, len(_HEADERS)):                self._tree.resizeColumnToContents(i)    # --- совместимость со старыми вызовами -----------------------------------    def display_series(self, series: ExperimentSeries) -> None:        """Алиас: добавить эксперимент (сохраняет имя метода из прежних версий)."""        self.append_series(series)    def append_result(self, result: ExperimentResult) -> None:        """Совместимость: одиночный результат без серии."""        exp_no = self._next_experiment_no        self._next_experiment_no += 1        exp_node = QTreeWidgetItem(self._tree)        exp_node.setText(            0,            f"Эксперимент {exp_no}  [{result.timestamp}]  "            f"сигнал: «{result.signal_name}», шум: «{result.noise_name}»",        )        exp_node.setText(1, "фильтров: 1, испытаний: 1")        bold = QFont(self._tree.font())        bold.setBold(True)        for col in range(len(_HEADERS)):            exp_node.setFont(col, bold)        filter_node = QTreeWidgetItem(exp_node)        filter_node.setText(0, f"Фильтр: {result.filter_name}")        filter_node.setText(1, "1")        filter_node.setText(2, "—")        filter_node.setText(3, _fmt_float(result.metrics.mse, "{:.4e}"))        filter_node.setText(4, _fmt_float(result.metrics.rmse, "{:.4e}"))        filter_node.setText(5, _fmt_float(result.metrics.snr_before_db, "{:.3f}"))        filter_node.setText(6, _fmt_float(result.metrics.snr_after_db, "{:.3f}"))        filter_node.setText(7, _fmt_float(result.metrics.snr_improvement_db,                                          "{:+.3f}"))        filter_node.setText(8, _fmt_float(result.metrics.correlation, "{:.4f}"))        for col in range(len(_HEADERS)):            filter_node.setFont(col, bold)        self._append_trial(filter_node, result)        exp_node.setExpanded(True)        filter_node.setExpanded(True)    def append_results(self, results: Iterable[ExperimentResult]) -> None:        for r in results:            self.append_result(r)    # --- управление содержимым ----------------------------------------------    def clear(self) -> None:        self._tree.clear()        self._next_experiment_no = 1    def row_count(self) -> int:        """Совокупное количество листовых записей (испытаний)."""        total = 0        for i in range(self._tree.topLevelItemCount()):            exp_node = self._tree.topLevelItem(i)            for j in range(exp_node.childCount()):                filter_node = exp_node.child(j)                total += filter_node.childCount()        return total    # ---------- internals ---------------------------------------------------    def _append_trial(self, parent: QTreeWidgetItem,                      result: ExperimentResult) -> None:        child = QTreeWidgetItem(parent)        m = result.metrics        child.setText(0, f"испытание {result.trial_index + 1}")        child.setText(1, str(result.trial_index + 1))        child.setText(2, str(result.seed))        child.setText(3, _fmt_float(m.mse, "{:.4e}"))        child.setText(4, _fmt_float(m.rmse, "{:.4e}"))        child.setText(5, _fmt_float(m.snr_before_db, "{:.3f}"))        child.setText(6, _fmt_float(m.snr_after_db, "{:.3f}"))        child.setText(7, _fmt_float(m.snr_improvement_db, "{:+.3f}"))        child.setText(8, _fmt_float(m.correlation, "{:.4f}"))        for col in range(1, len(_HEADERS)):            child.setTextAlignment(col, Qt.AlignRight | Qt.AlignVCenter)